import{_ as a,o,c as l,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"202. On Call Recall","description":"","frontmatter":{"title":"202. On Call Recall","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","allowances"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/202-on-call-recall.md","filePath":"ebas/mental-health/management-admin/hours-of-work/202-on-call-recall.md"}'),n={name:"ebas/mental-health/management-admin/hours-of-work/202-on-call-recall.md"};function r(s,e,h,i,c,p){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="_202-on-call-recall" tabindex="-1">202. On Call Recall <a class="header-anchor" href="#_202-on-call-recall" aria-label="Permalink to &quot;202. On Call Recall&quot;">​</a></h1><p><strong>202.1</strong> The Employer shall pay an on-call allowance to Employees who are required to be on call.</p><p><strong>202.2</strong> Oncall Allowance</p><p><strong>(a)</strong> An Employee rostered to be on-call will be paid the &#39;on-call allowance&#39; set in Appendix 2 per 24-hour period or part thereof commencing with the following rates:</p><p><strong>(i)</strong> Monday to Friday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> Saturday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a></p><p><strong>(iii)</strong> Sunday or public holiday – as per schedule 2; and</p><p><strong>(iv)</strong> Weekend public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(b)</strong> The telephone allowance in the 2020 Agreement does not apply from FFPPOA 20 May 2025 and has been included in the rates at 202.2(a)above.</p><p><strong>(c)</strong> An Employee rostered to be on-call for a period spanning two days over which two different on-call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>202.3</strong> Recall</p><p><strong>(a)</strong> Where an Employee is recalled to duty during an off-duty period they shall be paid a minimum of three (3) hours at the appropriate rate.</p><p><strong>(b)</strong> When recall work is necessary, it should be so arranged that Employees have at least 8 hours off duty between midnight and the commencement of the next period of ordinary duty.</p><p><strong>(c)</strong> An Employee, other than a casual, who works so much overtime between the termination of their previous rostered shift an the commencement of their next rostered shift, that they would not have a 8-hour break shall be released after completion of such recall worked until they have had a 8-hour break. The Employee shall not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>(d)</strong> If, on the instructions of the Employer, an Employee resumes or continues work without having had an 8-hour break in accordance with clause 202.3(c)[223.2(v)], they shall be paid at the rate of double time until they are released from duty for such rest period. The Employee shall then be entitled to be absent until they have had an 8-hour break. The Employee shall not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>202.4</strong> Payment Exception - Royal Children&#39;s Hospital only Clause 202.2 does not apply to Employees who are classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> of this Agreement in Grade 3 or above. Such Employees shall be paid an annualised salary pursuant to <a href="/eba/ebas/mental-health/management-admin/wages/190-annualised-salaries-royal-children-s-hospital.html">clause 190</a></p>',16)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
